// Lookup maps
const bySlug = new Map<string, TeamMeta>();
const byName = new Map<string, TeamMeta>();
const byAbbr = new Map<string, TeamMeta>();

rawTeams.forEach(t => {
  bySlug.set(t.slug.toLowerCase(), t);
  byName.set(t.school.toLowerCase(), t);
  
  if (t.abbreviation && t.abbreviation !== "#null") {
    byAbbr.set(t.abbreviation.toLowerCase(), t);
  }
  
  t.alternateNames.forEach(alt => {
    const key = alt.toLowerCase().trim();
    if (!byName.has(key)) {
      byName.set(key, t);
    }
  });
});

/**
 * Robust lookup for teams by any common name, slug, or abbreviation.
 * Handles variations like "St." vs "State" and "Univ" vs "University".
 */
export function getTeamByNameOrSlug(input?: string): TeamMeta | undefined {
  if (!input) return undefined;
  const key = input.toLowerCase().trim();

  // 1. Direct match (Slug, School Name, Abbr, or Alt Name)
  let match = bySlug.get(key) || byName.get(key) || byAbbr.get(key);
  if (match) return match;

  // 2. Normalized fallback
  const normalize = (s: string) => s
    .replace(/\bs[it]\.?\b/g, 'state')
    .replace(/\bst\.?\b/g, 'saint')
    .replace(/\buniv\.?\b/g, 'university')
    .replace(/\bof\b/g, '')
    .replace(/[^a-z0-9]+/g, '')
    .trim();

  const normKey = normalize(key);
  
  // Search normalized names
  for (const team of rawTeams) {
    if (normalize(team.school) === normKey) return team;
    if (team.alternateNames.some(alt => normalize(alt) === normKey)) return team;
    if (team.slug.replace(/-/g, '') === normKey) return team;
  }

  return undefined;
}

export const allTeams = rawTeams;
export const fbsTeams = rawTeams.filter(t => t.classification === 'fbs');
